#![allow(dead_code)]
extern crate core;
pub const DEBUG: bool = true;

mod error;
mod expr;
mod init;
mod runtime_env;

mod transpiler {
    pub mod code_gen_context;
    pub mod compiletime_env;
    pub mod expr_to_c;
}
mod parser;
mod scanner;
mod span;
mod token;
mod token_type;
mod type_env;
mod value;
