279	    // Scope Management
280	
281	    pub fn push_scope(&mut self) {
282	        self.scopes.push(HashMap::new());
283	        self.current_scope += 1;
284	    }
285	
286	    pub fn pop_scope(&mut self) {
287	        self.scopes.pop();
288	        self.current_scope -= 1;
289	    }
290	
291	    // Variable Handling
292	
293	    pub fn declare_var(&mut self, name: String, is_mutable: bool, var_type: Type) -> usize {
294	        let id = self.next_var_id;
295	        self.next_var_id += 1;
296	
297	        let scope = self.scopes.last_mut().unwrap();
298	        scope.insert(name, (id, is_mutable, var_type));
299	
300	        id
301	    }
302	
303	    pub fn declare_global_var(&mut self, name: String, is_mutable: bool, var_type: Type) -> usize {
304	        let id = self.next_var_id;
305	        self.next_var_id += 1;
306	
307	        let scope = self.scopes.first_mut().unwrap();
308	        scope.insert(name, (id, is_mutable, var_type));
309	
310	        id
311	    }
312	
313	    fn resolve_var(&self, name: &str) -> Option<(usize, usize)> {
314	        for (idx, scope) in self.scopes.iter().enumerate().rev() {
315	            if let Some(id) = scope.get(name) {
316	                return Some((id.0, idx));
317	            }
318	        }
319	        None
320	    }
321	
322	    pub fn get_var(&self, name: &str) -> Option<(bool, Type)> {
323	        for scope in self.scopes.iter().rev() {
324	            if let Some((_id, is_mutable, var_type)) = scope.get(name) {
325	                return Some((*is_mutable, var_type.clone()));
326	            }
327	        }
328	        None
329	    }
330	
331	    pub fn var_exists(&self, name: &str) -> bool {
332	        for scope in self.scopes.iter().rev() {
333	            if let Some(_) = scope.get(name) {
334	                return true;
335	            }
336	        }
337	        false
338	    }
339	
340	    /// Returns the C variable name for variables.\
341	    /// Format: v_{id}s_{scope}
342	    pub fn c_var_name(&self, name: &str, span: Span) -> String {
343	        let (id, scope) = self.resolve_var(name).unwrap_or_else(|| {
344	            error(
345	                span,
346	                format!("Could not find variable '{}'", name).as_str(),
347	                "fetching variable name",
348	            );
349	            (0, 0)
350	        });
351	        format!("v_{}s_{}", id, scope)
352	    }
353	
354	    /// Returns the C variable name for a function instance with generics.\
355	    /// Format: v_{id}s_{scope}C{generic_types}D for generic functions, v_{id}s_{scope}CD for non-generic
356	    pub fn c_func_instance_name(&mut self, name: &str, generics: &[Type], span: Span) -> String {
357	        let (id, scope) = self.resolve_var(name).unwrap_or_else(|| {
358	            error(
359	                span,
360	                format!("Could not find variable '{}'", name).as_str(),
361	                "fetching function name",
362	            );
363	            (0, 0)
364	        });
365	
366	        let mut result = format!("v_{}s_{}", id, scope);
367	
368	        if generics.is_empty() {
369	            // Non-generic function: add CD suffix
370	            result.push_str("CD");
371	        } else {
372	            // Generic function: add C{generics}D
373	            result.push('C');
374	            for (i, g) in generics.iter().enumerate() {
375	                result.push_str(&self.c_type_name(g, span));
376	                if i != generics.len() - 1 {
377	                    result.push('_');
378	                }
379	            }
380	            result.push('D');
381	        }
382	
383	        result
384	    }
385	
386	    // Type Handling
387	
388	    pub fn register_type(&mut self, ty: Type) -> usize {
389	        if let Type::Conceptual(name) = &ty {
390	            panic!("Tried to register conceptual type: {}", name);
391	        }
392	
393	        let canonical_ty = self.canonicalize_type(ty);
394	
395	        if let Some(index) = self.all_types.iter().position(|t| t == &canonical_ty) {
396	            return index;
397	        }
398	
399	        let id = self.next_type_id;
400	        self.next_type_id += 1;
401	
402	        self.all_types.push(canonical_ty);
403	        id
404	    }
405	
406	    /// Returns the position of a type. Does not check if the type is generic
407	    fn get_simple_type_id(&self, name: &str) -> usize {
408	        if let Some(index) = self.all_types.iter().position(|t| t.name() == name) {
409	            return index;
410	        }
411	
412	        0
413	    }
414	    /// Returns the ID of a type. If the type is generic, it registers its generic types
415	    fn get_type_id(&mut self, ty: &Type) -> Option<usize> {
416	        let canonical = self.canonicalize_type(ty.clone());
417	        self.all_types.iter().position(|t| t == &canonical)
418	    }
419	
420	    /// Registers the generic types in a generic type
421	    fn canonicalize_type(&mut self, ty: Type) -> Type {
422	        let canonical_generics: Vec<Type> = ty
423	            .generics()
424	            .iter()
425	            .map(|g| {
426	                let id = self.register_type(g.clone());
