104	            Expr::Mult(l, r, span) => {
105	                Expr::CallFunc(
106	                    "_mult".into(),
107	                    vec![l.get_type(cte)],
108	                    vec![l.clone(), r.clone()],
109	                    *span,
110	                )
111	                .to_c(cte, ctx);
112	                false
113	            }
114	            Expr::EqualEqual(l, r, span) => {
115	                Expr::CallFunc(
116	                    "_equal".into(),
117	                    vec![l.get_type(cte)],
118	                    vec![l.clone(), r.clone()],
119	                    *span,
120	                )
121	                .to_c(cte, ctx);
122	                false
123	            }
124	            Expr::Greater(l, r, span) => {
125	                Expr::CallFunc(
126	                    "_greater".into(),
127	                    vec![l.get_type(cte)],
128	                    vec![l.clone(), r.clone()],
129	                    *span,
130	                )
131	                .to_c(cte, ctx);
132	                false
133	            }
134	            Expr::GreaterEqual(l, r, span) => {
135	                Expr::CallFunc(
136	                    "_greater_equal".into(),
137	                    vec![l.get_type(cte)],
138	                    vec![l.clone(), r.clone()],
139	                    *span,
140	                )
141	                .to_c(cte, ctx);
142	                false
143	            }
144	
145	            Expr::LessEqual(l, r, span) => {
146	                Expr::CallFunc(
147	                    "_less_equal".into(),
148	                    vec![l.get_type(cte)],
149	                    vec![l.clone(), r.clone()],
150	                    *span,
151	                )
152	                .to_c(cte, ctx);
153	                false
154	            }
155	
156	            Expr::BangEqual(l, r, span) => {
157	                Expr::CallFunc(
158	                    "_bang_equal".into(),
159	                    vec![l.get_type(cte)],
160	                    vec![l.clone(), r.clone()],
161	                    *span,
162	                )
163	                .to_c(cte, ctx);
164	                false
165	            }
166	
167	            Expr::StmtBlock(exprs, _span) => {
168	                for expr in exprs {
169	                    if expr.to_c(cte, ctx) {
170	                        ctx.body.push(';');
171	                    }
172	                    ctx.body.push('\n');
173	                }
174	                false
175	            }
176	
177	            Expr::If(if_cond, if_block, else_block, is_expr) => {
178	                if !is_expr {
179	                    ctx.body.push_str("if (");
180	                    if_cond.to_c(cte, ctx);
181	                    ctx.body.push_str(")");
182	                    if_block.to_c(cte, ctx);
183	                    if else_block.is_some() {
184	                        ctx.body.push_str(" else ");
185	                        else_block.clone().unwrap().to_c(cte, ctx);
186	                    }
187	                } else {
188	                    error(
189	                        if_cond.get_span(),
190	                        "EXPRESSION IF STATEMENTS NOT IMPLEMENTED",
191	                        "transpiling",
192	                    );
193	                }
194	
195	                let else_type = if let Some(ty) = else_block {
196	                    ty.get_type(cte)
197	                } else {
198	                    nil_type()
199	                };
200	                if if_block.get_type(cte) != else_type {
201	                    error(
202	                        if_block.get_span(),
203	                        "if and else blocks had different types",
204	                        "transpiling",
205	                    );
206	                }
207	
208	                false
209	            }
210	
211	            Expr::StmtBlockWithScope(exprs, span) => {
212	                cte.push_scope();
213	                ctx.body.push_str("{\n");
214	                Expr::StmtBlock(exprs.clone(), *span).to_c(cte, ctx);
215	                ctx.body.push('}');
216	                cte.pop_scope();
217	                false
218	            }
219	
220	            Expr::Print(expr, span) => {
221	                Expr::CallFunc(
222	                    "_print".into(),
223	                    vec![expr.get_type(cte)],
224	                    vec![expr.clone()],
225	                    *span,
226	                )
227	                .to_c(cte, ctx);
228	                true
229	            }
230	
231	            Expr::Discard(expr) => {
232	                expr.to_c(cte, ctx);
233	                true
234	            }
235	
236	            Expr::Variable(name, span) => {
237	                ctx.body.push_str(&cte.c_var_name(name, *span));
238	                false
239	            }
240	
241	            Expr::This(span) => {
242	                ctx.body.push(' ');
243	                ctx.body.push_str(&cte.c_var_name(cte.this(), *span));
244	                ctx.body.push(' ');
245	                false
246	            }
247	
248	            Expr::Declare(name, var_type, expr, is_mutable, span) => {
249	                let var_type = if var_type.is_some() {
250	                    cte.declare_var(name.clone(), *is_mutable, var_type.clone().unwrap());
251	                    var_type.clone().unwrap()
252	                } else {
253	                    let t = expr.clone().unwrap().get_type(cte);
254	                    cte.declare_var(name.clone(), *is_mutable, t.clone());
255	                    t
256	                };
257	
258	                ctx.body += format!(
259	                    "{} {}=",
260	                    cte.c_type_name(&var_type, *span),
261	                    cte.c_var_name(&name, *span),
262	                )
263	                .as_str();
264	                expr.clone().unwrap().to_c(cte, ctx);
265	                true
266	            }
267	
268	            Expr::CallFunc(name, gens, exprs, span) => {
269	                if !cte.var_exists(name) {
270	                    error(
271	                        *span,
272	                        &format!("Function '{}' does not exist", name),
273	                        "transpiling",
274	                    );
275	                }
276	                ctx.body
277	                    .push_str(format!("{}(", cte.c_func_instance_name(name, gens, *span)).as_str());
278	                for expr in exprs {
279	                    expr.to_c(cte, ctx);
280	                    ctx.body.push(',');
281	                }
282	                if exprs.len() >= 1 {
283	                    ctx.body.pop();
284	                }
285	
286	                ctx.body.push_str(")");
287	                true
288	            }
289	
290	            Expr::Stmt(expr) => {
291	                expr.to_c(cte, ctx);
292	                true
293	            }
294	
295	            Expr::DeclareFunction(name, block, return_type, args, _gens, span) => {
296	                let mut arg_types = vec![];
297	                for arg in args {
298	                    arg_types.push(arg.1.clone());
299	                }
300	
301	                let ret_type = block.returned_type(cte, *span);
302	                let return_type = if return_type.is_some() {
303	                    return_type.clone().unwrap()
304	                } else {
305	                    if let Some(ty) = ret_type.clone() {
306	                        ty
307	                    } else {
308	                        nil_type()
309	                    }
310	                };
311	
312	                ctx.body.push_str(
313	                    format!(
314	                        "{} {}(",
315	                        cte.c_type_name(&return_type, *span),
316	                        cte.c_func_instance_name(&name, &[], *span),
317	                    )
318	                    .as_str(),
319	                );
320	
321	                cte.push_scope();
322	                for arg in args {
323	                    cte.declare_var(arg.0.clone(), false, arg.1.clone());
324	                    ctx.body.push_str(&cte.c_type_name(&arg.1, *span));
325	                    ctx.body.push(' ');
326	                    ctx.body.push_str(&cte.c_var_name(&arg.0, *span));
327	                    ctx.body.push_str(", ");
328	                }
329	                if ctx.body.ends_with(", ") {
330	                    ctx.body.pop();
331	                    ctx.body.pop();
332	                }
333	
334	                ctx.body.push(')');
335	
336	                block.to_c(cte, ctx);
337	
338	                cte.pop_scope();
339	
340	                false
341	            }
342	
343	            Expr::Assign(name, expr, span) => {
344	                cte.push_this(name);
345	                ctx.body.push_str(&cte.c_var_name(&name, *span));
346	                ctx.body.push('=');
347	                expr.to_c(cte, ctx);
348	                cte.pop_this();
349	                true
350	            }
351	
352	            Expr::Return(expr, _span) => {
353	                ctx.body.push_str("return ");
354	                expr.to_c(cte, ctx);
355	                true
356	            }
357	
358	            Expr::Delete(name) => {
359	                cte.del_var(name);
360	                false
361	            }
362	
363	            Expr::Nothing() => false,
364	
365	            Expr::While(cond, block) => {
366	                ctx.body.push_str("while (");
367	                cond.to_c(cte, ctx);
368	                ctx.body.push_str("){\n");
369	                block.to_c(cte, ctx);
370	                ctx.body.push_str("}");
371	                false
372	            }
373	
374	            Expr::Input(name) => {
375	                ctx.body.push_str("scanf(\"%d\",&");
376	                ctx.body.push_str(&cte.c_var_name(name, Span::empty()));
377	                ctx.body.push_str(")");
378	                true
379	            }
380	
381	            Expr::Use { .. } => false,
382	
383	            _ => panic!("unexpected expression (for transpilation) '{:?}'", self),
384	        }
385	    }
386	
387	    pub fn pre_transpile(
388	        &self,
389	        cte: &mut CompileTimeEnv,
390	        ctx: &mut CodeGenContext,
391	        programs_to_transpile: &mut HashMap<String, bool>,
392	    ) {
393	        match self {
394	            Expr::DeclareFunction(name, block, return_type, args, _gens, span) => {
395	                if cte.get_var(name).is_some() {
396	                    error(
397	                    *span,
398	                    format!(
399	                        "Variable '{}' already exists and is immutable, could not declare function",
400	                        name
401	                    )
402	                        .as_str(),"pre-transpiling"
403	                );
404	                }
405	                let mut arg_types = vec![];
406	                for arg in args {
407	                    arg_types.push(arg.1.clone());
408	                }
409	
410	                let ret_type = block.returned_type(cte, *span);
411	                let return_type = if return_type.is_some() {
412	                    return_type.clone().unwrap()
413	                } else {
414	                    if let Some(ty) = ret_type.clone() {
415	                        ty
416	                    } else {
417	                        nil_type()
418	                    }
419	                };
420	
421	                cte.add_func_type(return_type.clone(), arg_types.clone(), ctx, *span);
422	                // Declare the variable first so c_func_instance_name can find it
423	                cte.declare_global_var(
424	                    name.clone(),
425	                    false,
426	                    Type::with_generics("func", {
427	                        arg_types.push(return_type.clone());
428	                        let output = arg_types;
429	                        output
430	                    }),
431	                );
432	
433	                ctx.declarations.push_str(
434	                    format!(
435	                        "{} {}(",
436	                        cte.c_type_name(&return_type, *span),
437	                        cte.c_func_instance_name(&name, &[], *span),
438	                    )
439	                    .as_str(),
440	                );
441	
442	                cte.push_scope();
443	                for arg in args {
444	                    cte.declare_var(arg.0.clone(), false, arg.1.clone());
445	                    ctx.declarations.push_str(&cte.c_type_name(&arg.1, *span));
446	                    ctx.declarations.push(' ');
447	                    ctx.declarations.push_str(&cte.c_var_name(&arg.0, *span));
448	                    ctx.declarations.push_str(", ");
449	                }
450	                if ctx.declarations.ends_with(", ") {
451	                    ctx.declarations.pop();
452	                    ctx.declarations.pop();
453	                }
454	
455	                ctx.declarations.push_str(");\n");
456	
457	                block.pre_transpile(cte, ctx, programs_to_transpile);
458	
459	                cte.pop_scope();
460	            }
461	            Expr::Use { kind, path, span } => {
462	                let crate_path = match kind {
463	                    UseKind::Std => STD_PATH,
464	                    UseKind::Normal => "",
465	                };
466	
467	                let full_path = format!("{}{}", crate_path, path);
468	
469	                if !Path::new(&full_path).exists() {
470	                    error(*span, "File does not exist!", "pre-transpiling");
471	                }
472	
473	                programs_to_transpile.insert(full_path, false);
474	            }
475	
476	            Expr::StmtBlock(exprs, _) | Expr::StmtBlockWithScope(exprs, _) => {
477	                for expr in exprs {
478	                    expr.pre_transpile(cte, ctx, programs_to_transpile);
479	                }
480	            }
481	
482	            Expr::Discard(expr) => expr.pre_transpile(cte, ctx, programs_to_transpile),
483	
484	            _ => {}
485	        }
486	    }
487	
488	    fn get_type(&self, cte: &CompileTimeEnv) -> Type {
489	        match self {
490	            Expr::Int(_) => "i32".into(),
491	            Expr::Float(_) => "f64".into(),
492	            Expr::Str(_) => "strlit".into(),
493	            Expr::Bool(_)
494	            | Expr::EqualEqual(..)
495	            | Expr::BangEqual(..)
496	            | Expr::Less(..)
497	            | Expr::LessEqual(..)
498	            | Expr::Greater(..)
499	            | Expr::GreaterEqual(..) => "bool".into(),
500	            Expr::Char(_) => "char".into(),
501	            Expr::Add(l, _, _)
502	            | Expr::Sub(l, ..)
503	            | Expr::Mult(l, ..)
504	            | Expr::Power(l, ..)
505	            | Expr::Div(l, ..) => l.get_type(cte),
506	            Expr::Return(expr, _span) => expr.get_type(cte),
507	            Expr::CallFunc(name, _, _, span) => {
508	                let function = cte
509	                    .get_var(name)
510	                    .unwrap_or_else(|| {
511	                        error(
512	                            *span,
513	                            &format!("Variable not defined: {}", name),
514	                            "type checker",
515	                        );
516	                        (false, nil_type())
517	                    })
518	                    .1;
519	                function.generics()[0].clone()
520	            }
521	            Expr::StmtBlock(exprs, _span) => exprs.last().unwrap().get_type(cte),
522	            Expr::StmtBlockWithScope(exprs, _span) => exprs.last().unwrap().get_type(cte),
523	            Expr::Variable(name, span) => {
524	                cte.get_var(name)
525	                    .unwrap_or_else(|| {
526	                        error(
527	                            *span,
528	                            &format!("Variable not defined: {}", name),
529	                            "type checker",
530	                        );
531	                        (false, nil_type())
532	                    })
533	                    .1
534	            }
535	            Expr::Discard(..) => nil_type(),
536	            Expr::Print(expr, _) => expr.get_type(cte),
537	            Expr::If(_, block, ..) => block.get_type(cte),
538	            _ => panic!("unexpected expression (for type check) '{:?}'", self),
539	        }
540	    }
541	
542	    fn returned_type(&self, cte: &CompileTimeEnv, span: Span) -> Option<Type> {
543	        match self {
544	            Expr::Return(expr, _span) => Some(expr.get_type(cte)),
545	            Expr::Discard(expr) => expr.returned_type(cte, span),
546	            Expr::StmtBlock(exprs, span) => {
547	                let mut return_type = None;
548	                for expr in exprs {
549	                    let ret_type = expr.returned_type(cte, *span);
550	                    if let Some(returned_type) = ret_type {
551	                        if let Some(expected_type) = return_type.clone() {
552	                            if expected_type != returned_type {
553	                                error(
554	                                    {
555	                                        let expr_span = expr.get_span();
556	                                        if expr_span == Span::empty() {
557	                                            *span
558	                                        } else {
559	                                            expr_span
560	                                        }
561	                                    },
562	                                    "Returned type was different to previous returned type",
563	                                    "returned type checker",
564	                                );
565	                            }
566	                        } else {
567	                            return_type = Some(returned_type);
568	                        }
569	                    }
570	                }
571	                return_type
572	            }
573	            Expr::StmtBlockWithScope(exprs, span) => {
574	                Expr::StmtBlock(exprs.clone(), *span).returned_type(cte, *span)
575	            }
576	            _ => None,
577	        }
578	    }
579	
580	    fn get_span(&self) -> Span {
581	        match self {
582	            Expr::Add(_, _, span)
583	            | Expr::Sub(_, _, span)
584	            | Expr::Mult(_, _, span)
585	            | Expr::Div(_, _, span)
586	            | Expr::Power(_, _, span)
587	            | Expr::Mod(_, _, span)
588	            | Expr::BangEqual(_, _, span)
589	            | Expr::EqualEqual(_, _, span)
590	            | Expr::GreaterEqual(_, _, span)
591	            | Expr::LessEqual(_, _, span)
592	            | Expr::Less(_, _, span)
593	            | Expr::Greater(_, _, span)
594	            | Expr::Return(_, span) => *span,
595	            _ => Span::empty(),
596	        }
597	    }
598	}
